"use strict";(self.webpackChunkdsanchezcr=self.webpackChunkdsanchezcr||[]).push([[477],{10:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"microsoft","metadata":{"permalink":"/blog/microsoft","source":"@site/blog/2022-09-20-LeavingMS.mdx","title":"I\'m leaving Microsoft","description":"Career update, I am leaving Microsoft","date":"2022-09-20T08:00:00.000Z","formattedDate":"September 20, 2022","tags":[{"label":"career update","permalink":"/blog/tags/career-update"}],"readingTime":0.555,"hasTruncateMarker":false,"authors":[{"name":"David Sanchez","url":"https://github.com/dsanchezcr","email":"davidsanchezaguilar@outlook.com","imageURL":"https://github.com/dsanchezcr.png","key":"dsanchezcr"}],"frontMatter":{"title":"I\'m leaving Microsoft","description":"Career update, I am leaving Microsoft","slug":"microsoft","authors":["dsanchezcr"],"tags":["career update"],"hide_table_of_contents":true,"image":"https://raw.githubusercontent.com/dsanchezcr/website/main/static/img/LeavingMS.jpg","date":"2022-09-20T08:00"},"nextItem":{"title":"A new website","permalink":"/blog/website"}},"content":"After almost 7 years, today is my last day at Microsoft. It has been great, I cannot say thank you enough to all the teammates, managers, and mentors I\'ve had over the years that have helped me grow and enjoy the journey.\\n\\nI will be eternally grateful to Microsoft for all the opportunities, experiences, learnings, all the support I received and especially for all the awesome people I met and had the opportunity to work with.\\n\\nWhile I am leaving Microsoft, my mission will continue. Tomorrow, I\'ll start a new adventure as an Azure & DevOps Consultant to continue helping people to build the most innovative solutions with technology.\\n\\n![Leaving Microsoft](../static/img/LeavingMS.jpg)"},{"id":"website","metadata":{"permalink":"/blog/website","source":"@site/blog/2022-09-01-website.mdx","title":"A new website","description":"Details about the tech behind my new website.","date":"2022-09-01T08:00:00.000Z","formattedDate":"September 1, 2022","tags":[{"label":"webiste","permalink":"/blog/tags/webiste"},{"label":"blog","permalink":"/blog/tags/blog"}],"readingTime":0.46,"hasTruncateMarker":false,"authors":[{"name":"David Sanchez","url":"https://github.com/dsanchezcr","email":"davidsanchezaguilar@outlook.com","imageURL":"https://github.com/dsanchezcr.png","key":"dsanchezcr"}],"frontMatter":{"title":"A new website","description":"Details about the tech behind my new website.","slug":"website","authors":["dsanchezcr"],"tags":["webiste","blog"],"hide_table_of_contents":true,"image":"https://raw.githubusercontent.com/dsanchezcr/website/main/static/img/DevOps-Conference.jpg","date":"2022-09-01T08:00"},"prevItem":{"title":"I\'m leaving Microsoft","permalink":"/blog/microsoft"}},"content":"Today I am relaunching my website based on [Docusarious from Facebook](https://docusaurus.io). I am running it on Azure Static Web Apps and GitHub Pages.\\n\\nA highlight from this static site generator is the localization functionality, as you can see, this websites supports English, Spanish and Portuguese.\\n\\nAnother thing, that liked me is the support of React, TypeScript and Markdown (including MDX).\\n\\nIn this blog I will be sharing tips about technology and, professional career development.\\n\\nIf you have any feedback or suggetion for content don\'t heasitate to reach out.\\n\\nThank you for reading!"}]}')}}]);